use std::collections::BinaryHeap;
use std::cmp::Ordering;

struct SpawnPoint {
    id: usize,
    distance: f64,
}

impl PartialEq for SpawnPoint {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for SpawnPoint {}

impl PartialOrd for SpawnPoint {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for SpawnPoint {
    fn cmp(&self, other: &Self) -> Ordering {
        if (self.distance - other.distance).abs() < f64::EPSILON {
            return self.id.cmp(&other.id); // Stable tie-breaker using ID
        }
        other.distance.partial_cmp(&self.distance).unwrap_or(Ordering::Equal)
    }
}

fn main() {
    let points = vec![
        SpawnPoint { id: 0, distance: 10.5 },
        SpawnPoint { id: 1, distance: 22.1 },
        SpawnPoint { id: 2, distance: 10.5 },
        SpawnPoint { id: 3, distance: 5.0 } 
    ];

    let mut heap = BinaryHeap::new();
    for point in points {
        heap.push(point);
    }

    println!("Sorted Spawn Points (Smallest Distance First):");
    while let Some(point) = heap.pop() {
        println!("ID: {}, Distance: {:.1}", point.id, point.distance);
    }
}

use std::collections::BinaryHeap;
use std::cmp::Ordering;

struct Record { 
    value: f64,
    id: u32,
    data: String,
}
impl PartialEq for Record {
    fn eq(&self, other: &Self) -> bool {
        self.value == other.value && self.id == other.id
    }
}
impl Eq for Record {}
impl PartialOrd for Record {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}
impl Ord for Record {
    fn cmp(&self, other: &Self) -> Ordering {
        let float_cmp = self.value.partial_cmp(&other.value).unwrap_or(Ordering::Equal);
        if float_cmp != Ordering::Equal {
            return float_cmp;
        }
        self.id.cmp(&other.id)
    }
}

fn main() {
    let mut records = vec![
        Record { value: 5.0, id: 1, data: "A".to_string() },
        Record { value: 2.1, id: 3, data: "C".to_string() },
        Record { value: 5.0, id: 2, data: "B".to_string() },
        Record { value: 2.1, id: 4, data: "D".to_string() },
    ];

    records.sort_by(|a, b| {
        let val_cmp = a.value.partial_cmp(&b.value).unwrap_or(Ordering::Equal);
        if val_cmp != Ordering::Equal {
            return val_cmp;
        }
        a.id.cmp(&b.id)
    });

    for record in records {
        println!("Value: {}, ID: {}, Data: {}", record.value, record.id, record.data);
    }
}

use std::collections::BTreeMap;

#[derive(Debug)]
struct Record {
    id: u32,
    data: String,
}

impl PartialEq for Record {
    fn eq(&self, other: &Self) -> bool {
        self.id == other.id && self.data == other.data
    }
}

impl Eq for Record {}

impl PartialOrd for Record {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Record {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.id.cmp(&other.id).then(self.data.cmp(&other.data))
    }
}

fn main() {
    let mut records = vec![Record { id: 2, data: "B".to_string() }, Record { id: 1, data: "A".to_string() }, Record { id: 2, data: "C".to_string() }];

    records.sort_by(|a, b| {
        if a.id == b.id {
            std::cmp::Ordering::Equal
        } else if a.id < b.id {
            std::cmp::Ordering::Less
        } else {
            std::cmp::Ordering::Greater
        }
    });

    records.sort_unstable_by(|a, b| {
        if a.id == b.id {
            std::cmp::Ordering::Equal
        } else if a.id < b.id {
            std::cmp::Ordering::Less
        } else {
            std::cmp::Ordering::Greater
        }
    });

    println!("Sorted result: {:?}", records);
}

use std::collections::BTreeMap;
use std::error::Error;

struct ConfigBlock {
    key: String,
    priority: i32,
    template_content: String,
}

fn process_sorted_configs(mut blocks: Vec<ConfigBlock>) -> Result<String, Box<dyn Error>> {
    blocks.sort_by_key(|b| std::cmp::Reverse(b.priority));

    let mut output = String::new();
    for block in blocks.iter().take(20) { // Simulate processing top 20 results
        output.push_str(&format!("<!-- Processed Block: {} (P: {}) -->n", block.key, block.priority));
        output.push_str(&block.template_content);
        output.push_str("n");
    }
    Ok(output)
}

